1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	};
8	
9	type Item = { type: string };
10	type Step = { op: string; items: Item[] };
11	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
12	
13	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
14	
15	const quoteStep = (step: Step): { premium: number } => {
16	  const base = step.items.reduce((sum, item) => sum + itemBasePremium(item), 0);
17	  const firstInsurance = base * FIRST_INSURANCE_RATE;
18	  return { premium: base + firstInsurance + PROCESSING_FEE };
19	};
20	
21	export const runScenario = (scenario: unknown): unknown => {
22	  const { steps } = scenario as Scenario;
23	  return { results: steps.map(quoteStep) };
24	};
25

